import { successResponse, errorResponse, outputAndExit } from '@/cli/output';

import { discoverResources } from '@/operations/discover';

import type { Command } from '@/types';
import type { DiscoverResourcesInput } from '@/operations/discover';

export const discoverCommand: Command<DiscoverResourcesInput> = async input => {
  const result = await discoverResources('cli:discover', input, {
    flags: input,
  });

  if (result.found) {
    return outputAndExit(successResponse(result), input);
  }

  const origin = 'origin' in result ? result.origin : input.url;
  return outputAndExit(
    errorResponse({
      code: 'GENERAL_ERROR',
      message:
        result.message ??
        `No OpenAPI spec found for ${origin}. Tried: /openapi.json, /.well-known/x402`,
      surface: 'cli:discover',
      cause: result.cause,
      details: { origin },
    }),
    input
  );
};
